diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..5c6c879dd810 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3345,6 +3345,73 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         return new ICmpInst(Pred, BOp0, Neg);
       }
     }
+    // Handle (add (zext/sext i1 X), (zext/sext i1 Y)) compared to constants.
+    // For zext: values are 0 or 1, so add can only be 0, 1, or 2.
+    // For sext: values are -1 or 0, so add can only be -2, -1, or 0.
+    Value *X, *Y;
+    // ZExt cases:
+    // (add (zext i1 X), (zext i1 Y)) == 0 --> nor(X, Y)
+    // (add (zext i1 X), (zext i1 Y)) == 1 --> xor(X, Y)
+    // (add (zext i1 X), (zext i1 Y)) == 2 --> and(X, Y)
+    // (add (zext i1 X), (zext i1 Y)) != 0 --> or(X, Y)
+    // (add (zext i1 X), (zext i1 Y)) != 1 --> eq(X, Y)
+    // (add (zext i1 X), (zext i1 Y)) != 2 --> nand(X, Y)
+    if (match(BO, m_c_Add(m_ZExt(m_Value(X)), m_ZExt(m_Value(Y)))) &&
+        X->getType()->isIntOrIntVectorTy(1) &&
+        Y->getType()->isIntOrIntVectorTy(1)) {
+      if (C.isZero()) {
+        // == 0: nor, != 0: or
+        Value *Or = BinaryOperator::CreateOr(X, Y);
+        if (isICMP_NE)
+          return replaceInstUsesWith(Cmp, Or);
+        return BinaryOperator::CreateXor(Or, ConstantInt::getTrue(X->getType()));
+      }
+      if (C.isOne()) {
+        // == 1: xor, != 1: eq
+        if (isICMP_NE)
+          return new ICmpInst(ICmpInst::ICMP_EQ, X, Y);
+        return BinaryOperator::CreateXor(X, Y);
+      }
+      if (C == 2) {
+        // == 2: and, != 2: nand
+        Value *And = BinaryOperator::CreateAnd(X, Y);
+        if (isICMP_NE)
+          return BinaryOperator::CreateXor(And, ConstantInt::getTrue(X->getType()));
+        return replaceInstUsesWith(Cmp, And);
+      }
+    }
+    // SExt cases:
+    // (add (sext i1 X), (sext i1 Y)) == -2 --> and(X, Y)
+    // (add (sext i1 X), (sext i1 Y)) == -1 --> xor(X, Y)
+    // (add (sext i1 X), (sext i1 Y)) == 0 --> nor(X, Y)
+    // (add (sext i1 X), (sext i1 Y)) != -2 --> nand(X, Y)
+    // (add (sext i1 X), (sext i1 Y)) != -1 --> eq(X, Y)
+    // (add (sext i1 X), (sext i1 Y)) != 0 --> or(X, Y)
+    if (match(BO, m_c_Add(m_SExt(m_Value(X)), m_SExt(m_Value(Y)))) &&
+        X->getType()->isIntOrIntVectorTy(1) &&
+        Y->getType()->isIntOrIntVectorTy(1)) {
+      const APInt &Val = C;
+      if (Val.isAllOnes() || Val == -2) {
+        // == -2: and, != -2: nand
+        Value *And = BinaryOperator::CreateAnd(X, Y);
+        if (isICMP_NE)
+          return BinaryOperator::CreateXor(And, ConstantInt::getTrue(X->getType()));
+        return replaceInstUsesWith(Cmp, And);
+      }
+      if (Val == -1) {
+        // == -1: xor, != -1: eq
+        if (isICMP_NE)
+          return new ICmpInst(ICmpInst::ICMP_EQ, X, Y);
+        return BinaryOperator::CreateXor(X, Y);
+      }
+      if (Val.isZero()) {
+        // == 0: nor, != 0: or
+        Value *Or = BinaryOperator::CreateOr(X, Y);
+        if (isICMP_NE)
+          return replaceInstUsesWith(Cmp, Or);
+        return BinaryOperator::CreateXor(Or, ConstantInt::getTrue(X->getType()));
+      }
+    }
     break;
   }
   case Instruction::Xor:

